    def publish_batch(
        self,
        user_data_list: list,
        event_type: str = "user_data_update",
    ) -> dict:
        """
        Publish a batch of user data messages (up to 10 per SQS batch).

        Args:
            user_data_list: List of dicts, each with 'user_data' and optionally 'user_id'.
            event_type: Event type for all messages in the batch.

        Returns:
            dict with successful and failed message details.
        """
        if not user_data_list:
            raise ValueError("user_data_list cannot be empty")

        all_successful = []
        all_failed = []

        # SQS allows max 10 messages per batch
        for batch_start in range(0, len(user_data_list), 10):
            batch_chunk = user_data_list[batch_start:batch_start + 10]
            entries = []

            for idx, item in enumerate(batch_chunk):
                user_data = item.get("user_data", item) if isinstance(item, dict) and "user_data" in item else item
                user_id = item.get("user_id") if isinstance(item, dict) else None

                self._validate_user_data(user_data)

                message_body = self._build_message_body(user_data, event_type)
                message_attributes = self._build_message_attributes(event_type, user_id)

                entry = {
                    "Id": str(idx),
                    "MessageBody": json.dumps(message_body, default=str),
                    "MessageAttributes": message_attributes,
                }

                if self.is_fifo:
                    entry["MessageGroupId"] = self.message_group_id or user_id or "default"
                    entry["MessageDeduplicationId"] = message_body["message_id"]

                entries.append(entry)

            try:
                response = self.sqs_client.send_message_batch(
                    QueueUrl=self.queue_url,
                    Entries=entries,
                )
                all_successful.extend(response.get("Successful", []))
                all_failed.extend(response.get("Failed", []))
            except ClientError as e:
                logger.error("Batch publish failed: %s", e.response["Error"]["Message"])
                raise

        logger.info(
            "Batch publish complete. Successful: %d, Failed: %d",
            len(all_successful),
            len(all_failed),
        )

        return {
            "successful": all_successful,
            "failed": all_failed,
            "total_sent": len(all_successful),
            "total_failed": len(all_failed),
        }

    @staticmethod
    def _validate_user_data(user_data: dict) -> None:
        """Validate user data before publishing."""
        if not isinstance(user_data, dict):
            raise ValueError("user_data must be a dictionary")
        if not user_data:
            raise ValueError("user_data cannot be empty")

        # Validate email format if present
        email = user_data.get("email")
        if email and (not isinstance(email, str) or "@" not in email):
            raise ValueError(f"Invalid email format: must contain '@'")

        # Validate phone number if present
        phone = user_data.get("phone_number")
        if phone and not isinstance(phone, str):
            raise ValueError("phone_number must be a string")

        # Check message size (SQS max is 256KB)
        serialized = json.dumps(user_data, default=str)
        if len(serialized.encode("utf-8")) > 200_000:  # Leave room for metadata
            raise ValueError("user_data exceeds maximum allowed size")


